from fastapi import FastAPI, HTTPException
from pydantic import BaseModel, Field
from web3 import Web3
from eth_account.messages import encode_defunct
from typing import Optional
import re

app = FastAPI(title="Ethereum Signature Auth Service")

ADDRESS_RE = re.compile(r"^0x[a-fA-F0-9]{40}$")


class AuthRequest(BaseModel):
    address: str = Field(..., description="Ethereum wallet address")
    message: str = Field(..., description="Original message that was signed")
    signature: str = Field(..., description="Hex-encoded signature")


class AuthResponse(BaseModel):
    authenticated: bool
    recovered_address: str
    normalized_address: str


def normalize_address(address: str) -> str:
    if not isinstance(address, str):
        raise ValueError("Invalid address")
    address = address.strip()
    if not ADDRESS_RE.match(address):
        raise ValueError("Invalid Ethereum address format")
    return Web3.to_checksum_address(address)


def recover_address(message: str, signature: str) -> str:
    if not isinstance(message, str) or not message:
        raise ValueError("Invalid message")
    if not isinstance(signature, str) or not signature:
        raise ValueError("Invalid signature")
    if not signature.startswith("0x"):
        signature = "0x" + signature
    encoded_message = encode_defunct(text=message)
    recovered = Web3().eth.account.recover_message(encoded_message, signature=signature)
    return Web3.to_checksum_address(recovered)


@app.get("/health")
def health():
    return {"status": "ok"}


@app.post("/auth/verify", response_model=AuthResponse)
def verify_auth(payload: AuthRequest):
    try:
        normalized_address = normalize_address(payload.address)
        recovered_address = recover_address(payload.message, payload.signature)
    except Exception as e:
        raise HTTPException(status_code=400, detail=str(e))

    authenticated = normalized_address == recovered_address

    return AuthResponse(
        authenticated=authenticated,
        recovered_address=recovered_address,
        normalized_address=normalized_address,
    )